import React, { useState } from 'react';
import ProfileForm from '../components/ProfileForm';
import RiskForm from '../components/RiskForm';
import CalorieUpload from '../components/CalorieUpload';
import ProgressChart from '../components/ProgressChart';
import NutrientWarning from '../components/NutientWarning';
import Recommendations from './Recommendations'; 


const DASHBOARD_MENU = [
    { id: 'profile', name: '👤 Profile & Goal', component: ProfileForm },
    { id: 'risk', name: '❤️ Health Risk Check', component: RiskForm },
    { id: 'calorie', name: '🥗 Calorie Estimation', component: CalorieUpload },
    { id: 'analytics', name: '📊 Daily Analytics', component: ProgressChart },
    { id: 'recommendations', name: '🧠 Personalized Plans', component: Recommendations },
];


const Dashboard = ({ profile, setProfile, fetchProfile }) => {
    // State to track which item in the sidebar is active
    const [activeModule, setActiveModule] = useState(DASHBOARD_MENU[0].id);
    
    // Find the component currently selected
    const ActiveComponent = DASHBOARD_MENU.find(item => item.id === activeModule)?.component;
    
    // Check for essential data needed for BMI/BMR/Risk Calculation
    const isProfileIncomplete = !profile.age || !profile.height || !profile.weight;

    // Props passed to the active component
    const componentProps = {
        profile,
        setProfile,
        fetchProfile,
        dailyCalorieTarget: profile.dailyCalorieTarget
    };
    
    // Determine the title of the active content pane
    const activeTitle = DASHBOARD_MENU.find(item => item.id === activeModule)?.name;


    // --- RENDERING ---
    return (
        <div className="flex min-h-[calc(100vh-68px)] bg-[#121212] text-white">

            {/* Left Sidebar (20%) */}
            <div className="w-1/5 bg-[#1E1E1E] p-4 shadow-xl border-r border-[#333]">
                <h3 className="text-lg font-semibold mb-6 text-ai-green">System Modules</h3>
                
                <div className="mb-8">
                    <NutrientWarning />
                </div>

                <div className="space-y-3">
                    {DASHBOARD_MENU.map((item) => (
                        <button
                            key={item.id}
                            onClick={() => setActiveModule(item.id)}
                            className={`w-full text-left p-3 rounded-lg transition-all text-sm font-medium
                                ${activeModule === item.id ? 
                                    'bg-accent-blue text-white shadow-md' : 
                                    'hover:bg-[#2D2D2D] text-gray-300'
                                }`}
                        >
                            {item.name}
                        </button>
                    ))}
                </div>
            </div>

            {/* Right Content Area (80%) */}
            <div className="w-4/5 p-8 bg-[#121212] overflow-y-auto">
                <div className="bg-card p-6 rounded-xl shadow-ai border border-[#2D2D2D]">
                    <h2 className="text-3xl font-bold mb-6 text-ai-green border-b border-[#333] pb-3">
                        {activeTitle}
                    </h2>

                    {/* Conditional Rendering of the Active Module */}
                    <div className="min-h-[600px]">
                        {ActiveComponent && (
                            // Render the component, applying conditional restrictions if needed
                            (activeModule === 'risk' && isProfileIncomplete) ? (
                                <p className="text-red-500 p-8">
                                    Please complete Age, Height, and Weight in the **Profile & Goal** module to check risk.
                                </p>
                            ) : (
                                <ActiveComponent {...componentProps} />
                            )
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Dashboard;
